/* STREAMING_CHUNK:Processing multiplexed candidate and job inputs safely with fallback patterns */
// Iterate through and output EVERY item in the multiplexed stream
return $input.all().map(item => {
  const data = item.json;

  // Defensive extraction for Candidate fields (Input 1 -> Primary suffix _1)
  const candidateId = data.id_1 ?? data.id ?? data.candidate_id;
  const candidateName = data.name_1 ?? data.name ?? "Unknown Candidate";

  // Safely handle candidate skills if they arrive as arrays, strings, or are missing
  let candidateSkills = data.skills_1 ?? data.skills;
  if (Array.isArray(candidateSkills)) {
    candidateSkills = candidateSkills.join(", ");
  } else if (typeof candidateSkills === 'string') {
    // Keep as string
  } else {
    candidateSkills = "No explicit skills listed";
  }

  // Safely handle candidate experience
  let candidateExperience = data.experience_1 ?? data.experience;
  if (Array.isArray(candidateExperience)) {
    candidateExperience = candidateExperience.join("\n");
  } else if (typeof candidateExperience === 'string') {
    // Keep as string
  } else {
    candidateExperience = "No experience description listed";
  }

  // Defensive extraction for Job fields (Input 2 -> Primary suffix _2)
  const jobId = data.id_2 ?? data.job_id ?? 1; // Fallback to 1 if entirely missing
  const jobTitle = data.title_2 ?? data.title ?? "Unknown Position";

  // Safely handle job requirements
  let jobRequirements = data.requirements_2 ?? data.requirements;
  if (Array.isArray(jobRequirements)) {
    jobRequirements = jobRequirements.join("\n");
  } else if (typeof jobRequirements === 'string') {
    // Keep as string
  } else {
    jobRequirements = "No specific requirements listed";
  }

  /* STREAMING_CHUNK:Constructing the LLM evaluation prompt context */
  // Build the context-rich prompt for Qwen
  const promptText = `
You are a senior technical recruiter and hiring manager. Evaluate the following candidate against the specified target job requirements.

### TARGET JOB:
- Job ID: ${jobId}
- Title: ${jobTitle}
- Requirements: 
${jobRequirements}

### CANDIDATE PROFILE:
- Candidate ID: ${candidateId}
- Name: ${candidateName}
- Key Skills: ${candidateSkills}
- Professional Experience:
${candidateExperience}

---

### EVALUATION INSTRUCTIONS:
Analyze the candidate's skills and experience against the job requirements.
Provide your evaluation in a valid, structured JSON format with the following keys:
1. "overall_score": An integer between 0 and 100 representing alignment.
2. "decision": String, strictly one of: "Proceed", "Hold", "Reject".
3. "strengths": An array of strings highlighting matching credentials/skills.
4. "missing_skills": An array of strings highlighting gaps.
5. "reasoning": A robust paragraph justifying your score and decision.
6. "summary": A concise, one-sentence elevator summary.

Respond ONLY with raw JSON. Do not write introductory text, markdown formatting blocks (like \`\`\`json), or conversational filler.
`;

  /* STREAMING_CHUNK:Structuring payload output for LM Studio and database lookup */
  // Return formatted cleanly in the required n8n wrapper [{ json: { ... } }]
  return {
    json: {
      lm_studio_prompt: {
        model: "qwen2.5-14b-instruct-1m",
        messages: [
          { 
            role: "system", 
            content: "You are a precise, objective screening assistant that outputs strict JSON matching the requested structure." 
          },
          { 
            role: "user", 
            content: promptText 
          }
        ],
        temperature: 0.15
      },
      // Persist critical relational tracking variables downstream for final save step
      candidate_database_id: candidateId,
      job_database_id: jobId
    }
  };
});

return $input.all().map(item => {
  try {
    // 🧠 Secure extraction checking both array index [0] and flat fallback paths
    let rawContent = "";

    if (item.json.choices && item.json.choices[0] && item.json.choices[0].message) {
      rawContent = item.json.choices[0].message.content;
    } else if (item.json.choices && item.json.choices.message) {
      rawContent = item.json.choices.message.content;
    } else {
      throw new Error("Model completion choices path not found in the payload payload object.");
    }

    rawContent = rawContent.trim();
    const parsedJson = JSON.parse(rawContent);

    return {
      json: {
        candidate_database_id: item.json.candidate_database_id,
        job_database_id: item.json.job_database_id,
        ...parsedJson   // Merge parsed properties from Qwen
      }
    };
  } catch (error) {
    return {
      json: {
        candidate_database_id: item.json.candidate_database_id,
        job_database_id: item.json.job_database_id,
        error: "Failed to parse model response text",
        raw_error_message: error.message
      }
    };
  }
});
